import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyTable, headerActions, breadCrumbActions, mainStageHeaderAction, mainStageHeaderStrings, InfoText, headerStrings } from '../../../includes';
import { Button } from '@material-ui/core';
import { colors } from '../../../../utils';
import { staffStrings } from '../config';
import { staffActions } from '../actions';
import { routeNamesSchool } from '../../routeNames';

const style = theme => ({
    root: {
        marginTop : 20
    },
    newBtn : {
        backgroundColor : colors.secondary
    }
})
class _TeacherStaff extends Component {
    constructor(props) {
        super(props);
        headerActions({
            [headerStrings.headerTitle] : "Staff (Teacher)",
            [headerStrings.backButtonAction] : null
        })(props.dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.buttons] : [{
                value : "New Teacher Staff", className : this.props.classes.newBtn, 
                onClick : ()=>this.props.history.push(routeNamesSchool.newTeacherStaff)
            }]
        })(props.dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesSchool.dashboard},
            {name : "Teacher Staff", path : routeNamesSchool.teacherStaff},
        ])(props.dispatch);
        staffActions.getStaff.teachers()(props.dispatch);
    }
    componentDidMount(){
    }
    newStaffButton = () => <Button style={{backgroundColor : colors.secondary}}>New Staff</Button>;
    header = ["", "Last Name", "First Name", "Address", "Email", "Phone"];
    dataMap = ["action", "lastName", "firstName", "address", "email", "phone"]
    render() {
        const {classes, [staffStrings.staffListTeacher] : teachers = []} = this.props;
        return (
            <div className={classes.root}>
                <InfoText>Click on the table row (staff) to select</InfoText>
                <MyTable
                    header={this.header}
                    dataMap={this.dataMap}
                    data={teachers}/>
            </div>
        );
    }
}


_TeacherStaff.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = ({staffReducer}) => ({
    [staffStrings.staffListTeacher] : staffReducer[staffStrings.staffListTeacher]
})


export const TeacherStaff = connect(mapStateToProps)(withStyles(style)(_TeacherStaff));
export {TeacherStaff as default};